fn form_item_asset_test_record(fields: Vec<String>) -> String {
    format!("{{{}}}", fields.join(","))
}

fn form_item_asset_test_fields(wrapper: &str, id: usize, len: usize) -> Vec<String> {
    let mut fields = vec!["0".to_string(); len];
    fields[0] = wrapper.to_string();
    fields[1] = format!("{{{id},0}}");
    fields
}

fn form_item_asset_test_picture_value(payload: &str) -> String {
    format!(r#"{{4,3,{{0}},"",-1,-1,0,{{{{#base64:{payload}}}}},0,""}}"#)
}

fn form_item_asset_test_body(items: &[String]) -> Vec<u8> {
    deflate_for_test(format!(r#"{{4,{{0}},"",{{2,{}}}}}"#, items.join(",")).as_bytes())
}

fn form_item_asset_test_decoration(id: usize, name: &str, payload: &str) -> String {
    let mut fields = form_item_asset_test_fields("12", id, 19);
    fields[5] = "1".to_string();
    fields[6] = format!(r#""{name}""#);
    fields[18] = format!("{{4,{}}}", form_item_asset_test_picture_value(payload));
    form_item_asset_test_record(fields)
}

fn form_item_asset_test_button(
    wrapper: &str,
    id: usize,
    name: &str,
    payload: &str,
    offset: usize,
) -> String {
    let mut fields = form_item_asset_test_fields(wrapper, id, 26 + offset);
    fields[5 + offset] = format!(r#""{name}""#);
    fields[25 + offset] = form_item_asset_test_picture_value(payload);
    form_item_asset_test_record(fields)
}

fn form_item_asset_test_table(wrapper: &str, id: usize, name: &str, payload: &str) -> String {
    let mut fields = form_item_asset_test_fields(wrapper, id, 45);
    fields[5] = format!(r#""{name}""#);
    fields[43] = "{0}".to_string();
    fields[44] = form_item_asset_test_picture_value(payload);
    form_item_asset_test_record(fields)
}

fn form_item_asset_test_picture_field(
    id: usize,
    name: &str,
    header_payload: Option<&str>,
    values_payload: Option<&str>,
    offset: usize,
) -> String {
    let mut fields = form_item_asset_test_fields("37", id, 40 + offset);
    fields[5 + offset] = "4".to_string();
    fields[6 + offset] = format!(r#""{name}""#);
    if let Some(payload) = header_payload {
        fields[29 + offset] = form_item_asset_test_picture_value(payload);
    }
    if let Some(payload) = values_payload {
        fields[39 + offset] = format!(
            "{{10,0,0,0,0,{}}}",
            form_item_asset_test_picture_value(payload)
        );
    }
    form_item_asset_test_record(fields)
}

#[test]
fn writes_form_item_pictures_to_source_layout() {
    let root = std::env::temp_dir().join(format!(
        "ibcmd-rs-mssql-dump-test-{}",
        uuid::Uuid::new_v4().hyphenated()
    ));
    fs::create_dir_all(&root).unwrap();
    let catalog_uuid = "aaaaaaaa-aaaa-4aaa-aaaa-aaaaaaaaaaaa";
    let form_uuid = "bbbbbbbb-bbbb-4bbb-bbbb-bbbbbbbbbbbb";
    let catalog_metadata = deflate_for_test(
            format!(
                "{{1,\r\n{{57,\r\n{{0,\r\n{{3,\r\n{{1,0,{catalog_uuid}}},\"Products\",{{1,\"en\",\"Products\"}},\"\"}}\r\n}},0,{form_uuid},{{99999999-9999-4999-8999-999999999999,1,{form_uuid}}}}}\r\n}}"
            )
            .as_bytes(),
        );
    let form_metadata = deflate_for_test(
            format!(
                "{{1,\r\n{{0,\r\n{{13,\r\n{{3,\r\n{{1,0,{form_uuid}}},\"ListForm\",{{1,\"en\",\"List form\"}},\"\"}},0,1,{{0}}\r\n}}\r\n}},0}}"
            )
            .as_bytes(),
        );
    let form_body = form_item_asset_test_body(&[
        form_item_asset_test_table("55", 59, "RenamedRows", "iVBORw0KGgo="),
        form_item_asset_test_picture_field(60, "RenamedValues", None, Some("iVBORw0KGgo="), 0),
    ]);
    let assets = extract_form_item_assets(&form_body);
    assert_eq!(
        assets
            .iter()
            .map(|asset| (asset.item_name.as_str(), asset.file_name.as_str()))
            .collect::<Vec<_>>(),
        vec![
            ("RenamedRows", "RowsPicture.png"),
            ("RenamedValues", "ValuesPicture.png")
        ]
    );
    let rows = vec![
        ConfigRow {
            file_name: catalog_uuid.to_string(),
            part_no: 0,
            data_size: catalog_metadata.len() as i64,
            binary_hex: encode_hex_for_test(&catalog_metadata),
        },
        ConfigRow {
            file_name: form_uuid.to_string(),
            part_no: 0,
            data_size: form_metadata.len() as i64,
            binary_hex: encode_hex_for_test(&form_metadata),
        },
        ConfigRow {
            file_name: format!("{form_uuid}.0"),
            part_no: 0,
            data_size: form_body.len() as i64,
            binary_hex: encode_hex_for_test(&form_body),
        },
    ];

    let dumped = dump_table_rows(&root, "Config", rows, false, false, true).unwrap();

    assert_eq!(dumped.source_asset_rows, 1);
    assert!(
        root.join("Catalogs/Products/Forms/ListForm/Ext/Form/Items/RenamedRows/RowsPicture.png")
            .exists()
    );
    assert!(
        root.join(
            "Catalogs/Products/Forms/ListForm/Ext/Form/Items/RenamedValues/ValuesPicture.png"
        )
        .exists()
    );

    let _ = fs::remove_dir_all(root);
}

#[test]
fn extracts_form_item_assets_from_structural_property_slots() {
    let body = form_item_asset_test_body(&[
        form_item_asset_test_decoration(1, "RenamedDecoration", "R0lGODlh"),
        form_item_asset_test_button("31", 2, "RenamedButton31", "iVBORw0KGgo=", 0),
        form_item_asset_test_button("34", 3, "RenamedButton34", "iVBORw0KGgo=", 1),
        form_item_asset_test_table("55", 4, "RenamedTable", "iVBORw0KGgo="),
        form_item_asset_test_picture_field(
            5,
            "RenamedPictureField",
            Some("iVBORw0KGgo="),
            Some("iVBORw0KGgo="),
            1,
        ),
    ]);

    let assets = extract_form_item_assets(&body)
        .into_iter()
        .map(|asset| (asset.item_name, asset.file_name))
        .collect::<Vec<_>>();

    assert_eq!(
        assets,
        vec![
            ("RenamedDecoration".to_string(), "Picture.gif".to_string()),
            ("RenamedButton31".to_string(), "Picture.png".to_string()),
            ("RenamedButton34".to_string(), "Picture.png".to_string()),
            ("RenamedTable".to_string(), "RowsPicture.png".to_string()),
            (
                "RenamedPictureField".to_string(),
                "HeaderPicture.png".to_string()
            ),
            (
                "RenamedPictureField".to_string(),
                "ValuesPicture.png".to_string()
            ),
        ]
    );
}

#[test]
fn rejects_form_item_assets_from_nearby_or_unrecognized_slots() {
    let picture = form_item_asset_test_picture_value("iVBORw0KGgo=");

    let mut near_button = form_item_asset_test_fields("31", 1, 26);
    near_button[5] = r#""NearButton""#.to_string();
    near_button[24] = picture.clone();

    let mut wrong_table_wrapper = form_item_asset_test_fields("73", 2, 45);
    wrong_table_wrapper[5] = r#""WrongTableWrapper""#.to_string();
    wrong_table_wrapper[43] = "{0}".to_string();
    wrong_table_wrapper[44] = picture.clone();

    let mut wrong_options = form_item_asset_test_fields("37", 3, 40);
    wrong_options[5] = "4".to_string();
    wrong_options[6] = r#""WrongOptions""#.to_string();
    wrong_options[39] = format!("{{11,0,0,0,0,{picture}}}");

    let mut reference_kind = form_item_asset_test_fields("37", 4, 40);
    reference_kind[5] = "4".to_string();
    reference_kind[6] = r#""ReferenceKind""#.to_string();
    reference_kind[29] = r#"{4,1,{0},"",-1,-1,0,{{#base64:iVBORw0KGgo=}},0,""}"#.to_string();

    let mut ambiguous_payload = form_item_asset_test_fields("55", 5, 45);
    ambiguous_payload[5] = r#""AmbiguousPayload""#.to_string();
    ambiguous_payload[43] = "{0}".to_string();
    ambiguous_payload[44] =
        r#"{4,3,{0},"",-1,-1,0,{{#base64:iVBORw0KGgo=},{#base64:iVBORw0KGgo=}},0,""}"#.to_string();

    let body = form_item_asset_test_body(&[
        form_item_asset_test_record(near_button),
        form_item_asset_test_record(wrong_table_wrapper),
        form_item_asset_test_record(wrong_options),
        form_item_asset_test_record(reference_kind),
        form_item_asset_test_record(ambiguous_payload),
    ]);

    assert!(extract_form_item_assets(&body).is_empty());
}

#[test]
fn extracts_picture_decoration_from_wrapper_12() {
    let field = r#"{12,{165,02023637-7868-4a5f-8576-835a76e0c9ba},0,0,0,1,"СостояниеКартинка",{1,0},{1,0},{#base64:R0lGODlh}}"#;
    let item = parse_form_child_item(
        field,
        None,
        None,
        &BTreeMap::new(),
        &BTreeMap::new(),
        &[],
        &BTreeMap::new(),
    )
    .unwrap();

    assert_eq!(item.tag, "PictureDecoration");
    assert_eq!(item.name, "СостояниеКартинка");
    assert_eq!(item.picture_file_name, Some("Picture.gif"));
    assert_eq!(item.extended_tooltip, None);

    let xml = format_form_child_items_xml(&[item], 1);

    assert!(xml.contains(r#"<PictureDecoration name="СостояниеКартинка" id="165">"#));
    assert!(xml.contains("<xr:Abs>Picture.gif</xr:Abs>"));
    assert!(xml.contains("<xr:LoadTransparent>false</xr:LoadTransparent>"));
    assert!(!xml.contains("<ExtendedTooltip"));

    let form_body = form_item_asset_test_body(&[
        form_item_asset_test_decoration(164, "RenamedDecorationA", "R0lGODlh"),
        form_item_asset_test_decoration(165, "RenamedDecorationB", "R0lGODlh"),
    ]);
    let assets = extract_form_item_assets(&form_body);
    assert_eq!(
        assets
            .iter()
            .map(|asset| (asset.item_name.as_str(), asset.file_name.as_str()))
            .collect::<Vec<_>>(),
        vec![
            ("RenamedDecorationA", "Picture.gif"),
            ("RenamedDecorationB", "Picture.gif")
        ]
    );
    assert!(assets.iter().all(|asset| asset.content == b"GIF89a"));
}

#[test]
fn extracts_picture_decoration_picture_ref_and_context_menu_from_live_blob() {
    let field = r#"{12,{56,02023637-7868-4a5f-8576-835a76e0c9ba},0,0,0,1,"Логотип",{1,1,{"ru","Логотип"}},{1,0},1,0,0,2,2,{3,3,{-22}},{7,3,0,1,100},{0,0,0},1,{4,{4,1,{0,1b11ff6e-925c-4556-9810-b7266ffb3e30},"",-1,-1,0,0,""},0,2,0,{1,0},{3,4,{0}},{3,0,{0},0,1,0,48312c09-257f-4b29-b280-284dd89efc1e},0,0,{0,1,0},0,100},1,{22,{57,02023637-7868-4a5f-8576-835a76e0c9ba},0,0,0,8,"ЛоготипКонтекстноеМеню",{1,0},{1,0},0,1,0,0,0,2,2,{3,4,{0}},{7,3,0,1,100},{0,0,0},1,{1,1},0,1,0,0,0,3,3,0},1,2,{1,{1,1,{"ru","Логотип"}},0},0,1,{12,{58,02023637-7868-4a5f-8576-835a76e0c9ba},0,0,0,0,"ЛоготипРасширеннаяПодсказка",{1,0},{1,0},1,0,0,2,2,{3,4,{0}},{7,3,0,1,100},{0,0,0},1,{5,0,0,3,0,{0,1,0},{3,4,{0}},{3,4,{0}},{3,0,{0},0,1,0,48312c09-257f-4b29-b280-284dd89efc1e}},0,1,2,{1,{1,0},0},0,0,1,0,0,1,0,3,3,0,0},1,0,0,1,0,3,3,0,0},1,0,1}"#;
    let item = parse_form_child_item(
        field,
        None,
        None,
        &BTreeMap::new(),
        &BTreeMap::new(),
        &[],
        &BTreeMap::from([(
            "1b11ff6e-925c-4556-9810-b7266ffb3e30".to_string(),
            "CommonPicture.БизнесСетьЛоготип".to_string(),
        )]),
    )
    .unwrap();

    assert_eq!(item.tag, "PictureDecoration");
    assert_eq!(
        item.picture_ref.as_deref(),
        Some("CommonPicture.БизнесСетьЛоготип")
    );
    assert!(!item.picture_load_transparent);
    assert_eq!(item.picture_size, Some("Proportionally"));
    assert_eq!(item.file_drag_mode, Some("AsFile"));
    assert_eq!(item.text_color.as_deref(), Some("style:BorderColor"));
    assert!(
        item.child_items
            .iter()
            .any(|child| child.tag == "ContextMenu" && child.name == "ЛоготипКонтекстноеМеню")
    );

    let xml = format_form_child_items_xml(&[item], 1);
    assert!(xml.contains("<TextColor>style:BorderColor</TextColor>"));
    assert!(xml.contains("<Title formatted=\"false\">"));
    assert!(xml.contains("<PictureSize>Proportionally</PictureSize>"));
    assert!(xml.contains("<xr:Ref>CommonPicture.БизнесСетьЛоготип</xr:Ref>"));
    assert!(xml.contains("<FileDragMode>AsFile</FileDragMode>"));
    assert!(xml.contains(r#"<ContextMenu name="ЛоготипКонтекстноеМеню" id="57"/>"#));
}

#[test]
fn extracts_picture_decoration_picture_size_without_file_drag_mode_from_live_blob() {
    let field = r#"{12,{6,02023637-7868-4a5f-8576-835a76e0c9ba},0,0,0,1,"КартинкаШаблонДокументаСQRКодом",{1,1,{"ru","Картинка шаблон документа СQRКодом"}},{1,0},1,50,7,2,2,{3,4,{0}},{7,3,0,1,100},{0,0,0},1,{4,{4,1,{0,8da0dcfb-6ece-4f68-abb1-e6f9897eec6b},"",-1,-1,0,0,""},0,2,0,{1,0},{3,4,{0}},{3,0,{0},0,1,0,48312c09-257f-4b29-b280-284dd89efc1e},0,0,{0,1,0},1,100},1,{22,{7,02023637-7868-4a5f-8576-835a76e0c9ba},0,0,0,8,"КартинкаШаблонДокументаСQRКодомКонтекстноеМеню",{1,0},{1,0},0,1,0,0,0,2,2,{3,4,{0}},{7,3,0,1,100},{0,0,0},1,{1,1},0,1,0,0,0,3,3,0},1,2,{1,{1,1,{"ru","Картинка шаблон документа СQRКодом"}},0},0,1,{12,{8,02023637-7868-4a5f-8576-835a76e0c9ba},0,0,0,0,"КартинкаШаблонДокументаСQRКодомРасширеннаяПодсказка",{1,0},{1,0},1,0,0,2,2,{3,4,{0}},{7,3,0,1,100},{0,0,0},1,{5,0,0,3,0,{0,1,0},{3,4,{0}},{3,4,{0}},{3,0,{0},0,1,0,48312c09-257f-4b29-b280-284dd89efc1e}},0,1,2,{1,{1,0},0},0,0,1,0,0,1,0,3,3,0,0},0,0,0,0,0,3,3,0,0}"#;
    let object_refs = BTreeMap::from([(
        "8da0dcfb-6ece-4f68-abb1-e6f9897eec6b".to_string(),
        "CommonPicture.QRКодНаДокументеБЭД".to_string(),
    )]);
    let item = parse_form_child_item(
        field,
        None,
        None,
        &BTreeMap::new(),
        &BTreeMap::new(),
        &[],
        &object_refs,
    )
    .unwrap();

    assert_eq!(item.tag, "PictureDecoration");
    assert_eq!(item.width.as_deref(), Some("50"));
    assert_eq!(item.height.as_deref(), Some("7"));
    assert_eq!(item.auto_max_width, None);
    assert_eq!(item.auto_max_height, Some(false));
    assert_eq!(item.picture_size, Some("Proportionally"));
    assert_eq!(
        item.picture_ref.as_deref(),
        Some("CommonPicture.QRКодНаДокументеБЭД")
    );
    assert_eq!(item.file_drag_mode, None);

    let xml = format_form_child_items_xml(&[item], 1);
    assert!(xml.contains("<Width>50</Width>"));
    assert!(!xml.contains("<AutoMaxWidth>false</AutoMaxWidth>"));
    assert!(xml.contains("<Height>7</Height>"));
    assert!(xml.contains("<AutoMaxHeight>false</AutoMaxHeight>"));
    assert!(xml.contains("<PictureSize>Proportionally</PictureSize>"));
    assert!(!xml.contains("<FileDragMode>AsFile</FileDragMode>"));

    let stretch_field = field.replace(
        r#"},"",-1,-1,0,0,""},0,2,0,{1,0}"#,
        r#"},"",-1,-1,0,0,""},0,1,0,{1,0}"#,
    );
    let stretch_item = parse_form_child_item(
        &stretch_field,
        None,
        None,
        &BTreeMap::new(),
        &BTreeMap::new(),
        &[],
        &object_refs,
    )
    .unwrap();
    assert_eq!(stretch_item.picture_size, Some("Stretch"));
    let stretch_xml = format_form_child_items_xml(&[stretch_item], 1);
    assert!(stretch_xml.contains("<PictureSize>Stretch</PictureSize>"));

    let real_size_field = field.replace(
        r#"},"",-1,-1,0,0,""},0,2,0,{1,0}"#,
        r#"},"",-1,-1,0,0,""},0,0,0,{1,0}"#,
    );
    let real_size_item = parse_form_child_item(
        &real_size_field,
        None,
        None,
        &BTreeMap::new(),
        &BTreeMap::new(),
        &[],
        &object_refs,
    )
    .unwrap();
    assert_eq!(real_size_item.picture_size, Some("RealSize"));
    let real_size_xml = format_form_child_items_xml(&[real_size_item], 1);
    assert!(!real_size_xml.contains("<PictureSize>RealSize</PictureSize>"));
}

