#[test]
fn canonicalizes_only_data_ui_picture_value_refs() {
    let raw = concat!(
        "<?xml version=\"1.0\" encoding=\"UTF-8\"?>\r\n",
        "<SchemaFile xmlns=\"\" xmlns:xsi=\"http://www.w3.org/2001/XMLSchema-instance\">\r\n",
        "\t<dataCompositionSchema xmlns=\"http://v8.1c.ru/8.1/data-composition-system/schema\">\r\n",
        "\t\t<value xmlns=\"http://v8.1c.ru/8.1/data-composition-system/core\" xmlns:sourceUi=\"http://v8.1c.ru/8.1/data/ui\" xsi:type=\"sourceUi:Picture\" ref=\"sourceUi:Canonicalized\"/>\r\n",
        "\t\t<value xmlns=\"http://v8.1c.ru/8.1/data-composition-system/core\" xmlns:sourceUi=\"http://v8.1c.ru/8.1/data/ui\" xsi:type=\"sourceUi:Picture\" ref=\"xs:string\"/>\r\n",
        "\t\t<value xmlns=\"http://v8.1c.ru/8.1/data-composition-system/core\" xmlns:sourceUi=\"http://v8.1c.ru/8.1/data/ui\" xsi:type=\"sourceUi:Picture\" ref=\"BarePicture\"/>\r\n",
        "\t\t<value xmlns=\"http://v8.1c.ru/8.1/data-composition-system/core\" xmlns:sourceUi=\"http://v8.1c.ru/8.1/data/ui\" xsi:type=\"sourceUi:Color\" ref=\"sourceUi:WrongType\"/>\r\n",
        "\t\t<other xmlns=\"http://v8.1c.ru/8.1/data-composition-system/core\" xmlns:sourceUi=\"http://v8.1c.ru/8.1/data/ui\" xsi:type=\"sourceUi:Picture\" ref=\"sourceUi:WrongElement\"/>\r\n",
        "\t</dataCompositionSchema>\r\n",
        "</SchemaFile>"
    );

    let xml = String::from_utf8(
        normalize_data_composition_schema_template_xml(
            raw.as_bytes(),
            &BTreeMap::new(),
            &BTreeMap::new(),
        )
        .unwrap(),
    )
    .unwrap();

    assert!(xml.contains(r#"<dcscor:value xsi:type="v8ui:Picture" ref="v8ui:Canonicalized"/>"#));
    assert!(xml.contains(r#"<dcscor:value xsi:type="v8ui:Picture" ref="xs:string"/>"#));
    assert!(xml.contains(r#"<dcscor:value xsi:type="v8ui:Picture" ref="BarePicture"/>"#));
    assert!(xml.contains(r#"<dcscor:value xsi:type="v8ui:Color" ref="sourceUi:WrongType"/>"#));
    assert!(xml.contains(r#"<dcscor:other xsi:type="v8ui:Picture" ref="sourceUi:WrongElement"/>"#));
}

#[test]
fn leaves_unresolved_and_non_style_dcs_color_values_unchanged() {
    let unknown_uuid = "33333333-3333-4333-8333-333333333333";
    let non_style_uuid = "44444444-4444-4444-8444-444444444444";
    let style_uuid = "55555555-5555-4555-8555-555555555555";
    let raw = format!(
        "<?xml version=\"1.0\" encoding=\"UTF-8\"?>\r\n\
<SchemaFile xmlns=\"\" xmlns:xsi=\"http://www.w3.org/2001/XMLSchema-instance\">\r\n\
\t<dataCompositionSchema xmlns=\"http://v8.1c.ru/8.1/data-composition-system/schema\">\r\n\
\t\t<value xmlns=\"http://v8.1c.ru/8.1/data-composition-system/core\" xmlns:v8ui=\"http://v8.1c.ru/8.1/data/ui\" xsi:type=\"v8ui:Color\">0:{unknown_uuid}</value>\r\n\
\t\t<value xmlns=\"http://v8.1c.ru/8.1/data-composition-system/core\" xmlns:v8ui=\"http://v8.1c.ru/8.1/data/ui\" xsi:type=\"v8ui:Color\">0:{non_style_uuid}</value>\r\n\
\t\t<value xmlns=\"http://v8.1c.ru/8.1/data-composition-system/core\" xmlns:v8ui=\"http://v8.1c.ru/8.1/data/ui\" xsi:type=\"v8ui:Color\">0:not-a-uuid</value>\r\n\
\t\t<value xmlns=\"http://v8.1c.ru/8.1/data-composition-system/core\" xmlns:v8ui=\"http://v8.1c.ru/8.1/data/ui\" xsi:type=\"v8ui:Color\">style:Existing</value>\r\n\
\t\t<other xmlns=\"http://v8.1c.ru/8.1/data-composition-system/core\" xmlns:v8ui=\"http://v8.1c.ru/8.1/data/ui\" xsi:type=\"v8ui:Color\">0:{style_uuid}</other>\r\n\
\t</dataCompositionSchema>\r\n\
</SchemaFile>"
    );
    let object_refs = BTreeMap::from([
        (non_style_uuid.to_string(), "Catalog.Products".to_string()),
        (style_uuid.to_string(), "StyleItem.Accent".to_string()),
    ]);

    let xml = String::from_utf8(
        normalize_data_composition_schema_template_xml(
            raw.as_bytes(),
            &BTreeMap::new(),
            &object_refs,
        )
        .unwrap(),
    )
    .unwrap();

    assert!(xml.contains(&format!(">0:{unknown_uuid}</dcscor:value>")));
    assert!(xml.contains(&format!(">0:{non_style_uuid}</dcscor:value>")));
    assert!(xml.contains(">0:not-a-uuid</dcscor:value>"));
    assert!(xml.contains(">style:Existing</dcscor:value>"));
    assert!(xml.contains(&format!(">0:{style_uuid}</dcscor:other>")));
}

#[test]
fn merges_self_contained_inline_area_template_schema() {
    let raw = concat!(
        "\0\0\0\0",
        "<?xml version=\"1.0\" encoding=\"UTF-8\"?>\r\n",
        "<SchemaFile xmlns=\"\">\r\n",
        "\t<dataCompositionSchema xmlns=\"http://v8.1c.ru/8.1/data-composition-system/schema\">\r\n",
        "\t\t<dataSource><name>Source</name></dataSource>\r\n",
        "\t</dataCompositionSchema>\r\n",
        "</SchemaFile>",
        "<?xml version=\"1.0\" encoding=\"UTF-8\"?>\r\n",
        "<SchemaFile xmlns=\"\" xmlns:xsi=\"http://www.w3.org/2001/XMLSchema-instance\">\r\n",
        "\t<dataCompositionSchema xmlns=\"http://v8.1c.ru/8.1/data-composition-system/schema\">\r\n",
        "\t\t<template><name>Inline</name>",
        "<template xmlns:dcsat=\"http://v8.1c.ru/8.1/data-composition-system/area-template\" xsi:type=\"dcsat:AreaTemplate\">",
        "<dcsat:item xsi:type=\"dcsat:Field\"/>",
        "</template></template>\r\n",
        "\t</dataCompositionSchema>\r\n",
        "</SchemaFile>"
    );

    let xml = String::from_utf8(
        normalize_data_composition_schema_template_xml(
            raw.as_bytes(),
            &BTreeMap::new(),
            &BTreeMap::new(),
        )
        .unwrap(),
    )
    .unwrap();

    assert!(xml.contains("<name>Inline</name>"));
    assert!(xml.contains(
        r#"<template xmlns:dcsat="http://v8.1c.ru/8.1/data-composition-system/area-template" xsi:type="dcsat:AreaTemplate">"#
    ));
    assert!(xml.contains(r#"<dcsat:item xsi:type="dcsat:Field"/>"#));
    assert_eq!(xml.matches("<DataCompositionSchema ").count(), 1);
    assert!(!xml.contains("SchemaFile"));
}

