#[test]
fn formats_moxel_renumbers_formats_by_usage_order() {
    let spreadsheet = MoxelSpreadsheet {
        column_count: 2,
        column_sets: vec![MoxelColumnSet {
            id: None,
            default_format_index: None,
            source_default_format_index: None,
            size: 2,
            columns: vec![
                MoxelColumn {
                    index: 0,
                    format_index: 4,
                    source_format_index: None,
                },
                MoxelColumn {
                    index: 1,
                    format_index: 2,
                    source_format_index: None,
                },
            ],
        }],
        column_formats: vec![
            MoxelFormat {
                width: Some(10),
                ..MoxelFormat::default()
            },
            MoxelFormat {
                width: Some(20),
                ..MoxelFormat::default()
            },
            MoxelFormat {
                width: Some(30),
                ..MoxelFormat::default()
            },
            MoxelFormat {
                width: Some(40),
                ..MoxelFormat::default()
            },
        ],
        extra_formats: BTreeMap::new(),
        default_format_width: None,
        default_format: MoxelFormat {
            width: Some(70),
            ..MoxelFormat::default()
        },
        formats: vec![
            MoxelFormat {
                width: Some(50),
                ..MoxelFormat::default()
            },
            MoxelFormat {
                width: Some(60),
                ..MoxelFormat::default()
            },
        ],
        rows: vec![MoxelRow {
            index: 0,
            index_to: None,
            format_index: 6,
            source_format_index: Some(6),
            columns_id: None,
            cells: vec![MoxelCell {
                column_index: 0,
                format_index: 5,
                source_format_index: Some(5),
                text: Some("Cell".to_string()),
                parameter: None,
                detail_parameter: None,
                empty_text: false,
            }],
        }],
        vertical_groups: Vec::new(),
        merges: Vec::new(),
        horizontal_unmerges: Vec::new(),
        vertical_unmerges: Vec::new(),
        named_items: Vec::new(),
        areas: Vec::new(),
        print_area: None,
        print_settings: None,
        lines: Vec::new(),
        fonts: Vec::new(),
        drawings: vec![MoxelDrawing {
            id: 0,
            format_index: 3,
            begin_row: 0,
            begin_row_offset: 0,
            end_row: 0,
            end_row_offset: 0,
            begin_column: 0,
            begin_column_offset: 0,
            end_column: 0,
            end_column_offset: 0,
            auto_size: true,
            picture_size: "Auto",
            z_order: 0,
            picture_index: 0,
        }],
        pictures: Vec::new(),
        empty_headers_footers: false,
        header_footer_format_index: None,
        default_format_index: Some(7),
        height: 1,
    };

    let xml = format_moxel_spreadsheet_xml(&spreadsheet);

    assert_eq!(
        moxel_output_format_indices(&spreadsheet),
        vec![4, 2, 6, 5, 3, 7, 1]
    );
    assert!(
        xml.contains("<index>0</index>\r\n\t\t\t<column>\r\n\t\t\t\t<formatIndex>1</formatIndex>")
    );
    assert!(
        xml.contains("<index>1</index>\r\n\t\t\t<column>\r\n\t\t\t\t<formatIndex>2</formatIndex>")
    );
    assert!(xml.contains("<row>\r\n\t\t\t<formatIndex>3</formatIndex>"));
    assert!(xml.contains("<f>4</f>\r\n\t\t\t\t\t<tl>"));
    assert!(xml.contains("<drawing>\r\n\t\t<drawingType>Picture</drawingType>\r\n\t\t<id>0</id>\r\n\t\t<formatIndex>5</formatIndex>"));
    assert!(xml.contains("<defaultFormatIndex>6</defaultFormatIndex>"));
    assert!(xml.contains(
            "\t<format>\r\n\t\t<width>40</width>\r\n\t</format>\r\n\t<format>\r\n\t\t<width>20</width>\r\n\t</format>\r\n\t<format>\r\n\t\t<width>60</width>\r\n\t</format>\r\n\t<format>\r\n\t\t<width>50</width>\r\n\t</format>\r\n\t<format>\r\n\t\t<width>30</width>\r\n\t</format>\r\n\t<format>\r\n\t\t<width>70</width>\r\n\t</format>\r\n\t<format>\r\n\t\t<width>10</width>\r\n\t</format>"
        ));
}

