fn exchange_plan_owner_object_for_test(
    exchange_plan_uuid: &str,
    code: &str,
    tail: &[String],
    sentinel: Option<&str>,
) -> String {
    assert_eq!(tail.len(), 37);
    let mut fields = vec![
        code.to_string(),
        "22222222-2222-4222-8222-222222222221".to_string(),
        "22222222-2222-4222-8222-222222222222".to_string(),
        "33333333-3333-4333-8333-333333333331".to_string(),
        "33333333-3333-4333-8333-333333333332".to_string(),
        "55555555-5555-4555-8555-555555555551".to_string(),
        "55555555-5555-4555-8555-555555555552".to_string(),
        "66666666-6666-4666-8666-666666666661".to_string(),
        "66666666-6666-4666-8666-666666666662".to_string(),
        "44444444-4444-4444-8444-444444444441".to_string(),
        "44444444-4444-4444-8444-444444444442".to_string(),
        "aaaaaaaa-aaaa-4aaa-8aaa-aaaaaaaaaaaa".to_string(),
        format!(
            "{{3,{{1,0,{exchange_plan_uuid}}},\"Sync\",{{1,\"en\",\"Sync\"}},\"exchange comment\",0,0,00000000-0000-0000-0000-000000000000,0}}"
        ),
    ];
    fields.extend_from_slice(tail);
    if let Some(sentinel) = sentinel {
        fields.push(sentinel.to_string());
    }
    format!("{{{}}}", fields.join(","))
}

fn exact_exchange_plan_root_with_collections_for_test(
    exchange_plan_uuid: &str,
    code: &str,
    tail: &[String],
    sentinel: Option<&str>,
    collections: [&str; 5],
) -> String {
    let owner = exchange_plan_owner_object_for_test(exchange_plan_uuid, code, tail, sentinel);
    format!(
        "{{1,{owner},5,{},{},{},{},{}}}",
        collections[0], collections[1], collections[2], collections[3], collections[4]
    )
}

fn exact_exchange_plan_root_for_test(
    exchange_plan_uuid: &str,
    code: &str,
    tail: &[String],
) -> String {
    exact_exchange_plan_root_with_collections_for_test(
        exchange_plan_uuid,
        code,
        tail,
        (code == "37").then_some("1"),
        [
            "{1a1b4fea-e093-470d-94ff-1d2f16cda2ab,0}",
            "{3daea016-69b7-4ed4-9453-127911372fe6,0}",
            "{52293f4b-f98c-43ea-a80f-41047ae7ab58,0}",
            "{87c509ab-3d38-4d67-b379-aca796298578,0}",
            "{d5207c64-11d5-4d46-bba2-55b7b07ff4eb,0}",
        ],
    )
}

