#[test]
fn parses_exact_information_register_legacy_and_new_child_wrappers() {
    let child_uuid = "22222222-2222-4222-8222-222222222222";
    let common = information_register_common_child_for_test(child_uuid);
    let header = information_register_child_header_for_test(child_uuid);
    let zero_uuid = "00000000-0000-0000-0000-000000000000";
    let cases = [
        (
            "Resource",
            format!("{{7,{common},0,1,1}}"),
            None,
            "DontIndex",
            "Use",
        ),
        (
            "Resource",
            format!("{{8,{common},0,1,1,0,{{1,{zero_uuid}}}}}"),
            None,
            "DontIndex",
            "Use",
        ),
        (
            "Attribute",
            format!("{{4,{common},0,1,1}}"),
            None,
            "DontIndex",
            "Use",
        ),
        (
            "Attribute",
            format!("{{5,{common},0,1,1,0,{{1,{zero_uuid}}}}}"),
            None,
            "DontIndex",
            "Use",
        ),
        (
            "Dimension",
            format!("{{9,{common},1,0,2,1,1,0}}"),
            Some("TransformValues"),
            "IndexWithAdditionalOrder",
            "DontUse",
        ),
        (
            "Dimension",
            format!("{{10,{common},1,0,2,1,1,0,1}}"),
            Some("DeleteData"),
            "IndexWithAdditionalOrder",
            "DontUse",
        ),
    ];

    for (tag, wrapper, expected_type_reduction_mode, expected_indexing, expected_data_history) in
        cases
    {
        let fields = split_1c_braced_fields(&wrapper, 0).unwrap();
        let (value_types, properties) = parse_information_register_child_payload_from_fields(
            &fields,
            &header,
            "Rates",
            tag,
            &BTreeMap::new(),
            &BTreeMap::new(),
            &BTreeMap::new(),
            false,
        )
        .unwrap_or_else(|| panic!("failed to parse {tag}: {wrapper}"));

        assert_eq!(value_types, vec![ConstantValueType::Boolean]);
        assert_eq!(properties.quick_choice, Some("Auto"));
        assert_eq!(properties.create_on_input, Some("Use"));
        assert_eq!(properties.choice_history_on_input, Some("DontUse"));
        assert_eq!(properties.indexing, Some(expected_indexing));
        assert_eq!(properties.full_text_search, Some("Use"));
        assert_eq!(properties.data_history, Some(expected_data_history));
        assert_eq!(properties.type_reduction_mode, expected_type_reduction_mode);
        assert!(matches!(
            properties.fill_value,
            Some(MetadataChildFillValue::Boolean(true))
        ));
        if tag == "Dimension" {
            assert_eq!(properties.master, Some(true));
            assert_eq!(properties.main_filter, Some(true));
            assert_eq!(properties.deny_incomplete_values, Some(false));
            let mut xml = String::new();
            push_metadata_child_properties_xml(&mut xml, "\t", &properties);
            let ordered = [
                "<ChoiceHistoryOnInput>",
                "<Master>",
                "<MainFilter>",
                "<DenyIncompleteValues>",
                "<Indexing>",
                "<FullTextSearch>",
                "<DataHistory>",
                "<TypeReductionMode>",
            ]
            .map(|tag| xml.find(tag).unwrap());
            assert!(ordered.windows(2).all(|pair| pair[0] < pair[1]), "{xml}");
        } else {
            assert_eq!(properties.master, None);
            assert_eq!(properties.main_filter, None);
            assert_eq!(properties.deny_incomplete_values, None);
        }
    }
}

#[test]
fn parses_information_register_variable_collections_without_partial_results() {
    let path_uuid = "11111111-1111-4111-8111-111111111111";
    let owner_uuid = "22222222-2222-4222-8222-222222222222";
    let value_uuid = "33333333-3333-4333-8333-333333333333";
    let second_value_uuid = "44444444-4444-4444-8444-444444444444";
    let unresolved_path_uuid = "55555555-5555-4555-8555-555555555555";
    let cross_owner_value_uuid = "66666666-6666-4666-8666-666666666666";
    let child_owner_uuid = "77777777-7777-4777-8777-777777777777";
    let root_value_uuid = "88888888-8888-4888-8888-888888888888";
    let value_type_uuid = DESIGN_TIME_REF_TYPE_UUID;
    let array_type_uuid = FIXED_ARRAY_TYPE_UUID;
    let mut object_refs = BTreeMap::new();
    let mut type_index = BTreeMap::new();
    object_refs.insert(
        path_uuid.to_string(),
        "InformationRegister.Rates.Dimension.Target".to_string(),
    );
    type_index.insert(owner_uuid.to_string(), "cfg:EnumRef.Status".to_string());
    object_refs.insert(
        value_uuid.to_string(),
        "Enum.Status.EnumValue.Active".to_string(),
    );
    object_refs.insert(
        second_value_uuid.to_string(),
        "Enum.Status.EnumValue.Closed".to_string(),
    );
    object_refs.insert(
        cross_owner_value_uuid.to_string(),
        "Enum.OtherStatus.EnumValue.Active".to_string(),
    );
    object_refs.insert(
        child_owner_uuid.to_string(),
        "Enum.Status.EnumValue.Active".to_string(),
    );
    object_refs.insert(root_value_uuid.to_string(), "Enum.Status".to_string());

    let links = parse_information_register_choice_parameter_links(
        &format!("{{5006,2,\"First\",2,{{-2}},{{0,{path_uuid}}},0,\"Second\",1,{{-3}},1}}"),
        "Rates",
        &object_refs,
        false,
    )
    .unwrap();
    assert_eq!(links.len(), 2);
    assert_eq!(
        links[0].data_path,
        "InformationRegister.Rates.StandardAttribute.Period/InformationRegister.Rates.Dimension.Target"
    );
    assert_eq!(links[0].value_change, "Clear");
    assert_eq!(
        links[1].data_path,
        "InformationRegister.Rates.StandardAttribute.Recorder"
    );
    assert_eq!(links[1].value_change, "DontChange");

    let raw_links = parse_information_register_choice_parameter_links(
        &format!("{{5006,1,\"First\",1,{{0,{path_uuid}}},0}}"),
        "Rates",
        &object_refs,
        true,
    )
    .unwrap();
    assert_eq!(raw_links[0].data_path, format!("0:{path_uuid}"));

    let link_by_type = parse_information_register_link_by_type(
        &format!("{{3,2,{{0,{unresolved_path_uuid}}},{{0}},3}}"),
        "Rates",
        &object_refs,
        false,
    )
    .unwrap()
    .unwrap();
    assert_eq!(
        link_by_type.data_path,
        format!("0:{unresolved_path_uuid}/0")
    );
    assert_eq!(link_by_type.link_item, 3);
    let raw_link_by_type = parse_information_register_link_by_type(
        &format!("{{3,1,{{0,{path_uuid}}},0}}"),
        "Rates",
        &object_refs,
        true,
    )
    .unwrap()
    .unwrap();
    assert_eq!(raw_link_by_type.data_path, format!("0:{path_uuid}"));

    let reference = format!("{{\"#\",{value_type_uuid},{{0,{owner_uuid},{value_uuid}}}}}");
    let second_reference =
        format!("{{\"#\",{value_type_uuid},{{0,{owner_uuid},{second_value_uuid}}}}}");
    let parameters = parse_information_register_choice_parameters(
        &format!(
            "{{0,5,\"Bool\",{{\"B\",1}},\"Text\",{{\"S\",\"value\"}},\"Nil\",{{\"U\"}},\"Ref\",{reference},\"Array\",{{\"#\",{array_type_uuid},{{2,{reference},{second_reference}}}}}}}"
        ),
        &type_index,
        &object_refs,
    )
    .unwrap();
    assert_eq!(parameters.len(), 5);
    assert!(matches!(
        parameters[0].value,
        MetadataChoiceParameterValue::Boolean(true)
    ));
    assert!(matches!(
        parameters[1].value,
        MetadataChoiceParameterValue::String(ref value) if value == "value"
    ));
    assert!(matches!(
        parameters[2].value,
        MetadataChoiceParameterValue::Nil
    ));
    assert!(matches!(
        parameters[3].value,
        MetadataChoiceParameterValue::DesignTimeRef(ref value)
            if value == "Enum.Status.EnumValue.Active"
    ));
    assert!(matches!(
        parameters[4].value,
        MetadataChoiceParameterValue::FixedArray(ref values)
            if matches!(
                values.as_slice(),
                [
                    MetadataChoiceParameterValue::DesignTimeRef(first),
                    MetadataChoiceParameterValue::DesignTimeRef(second),
                ] if first == "Enum.Status.EnumValue.Active"
                    && second == "Enum.Status.EnumValue.Closed"
            )
    ));
    assert!(matches!(
        parse_information_register_fill_value(
            &format!(
                "{{\"#\",{value_type_uuid},{{0,{owner_uuid},00000000-0000-0000-0000-000000000000}}}}"
            ),
            &type_index,
            &object_refs,
        ),
        Some(MetadataChildFillValue::DesignTimeRef(ref value))
            if value == "Enum.Status.EmptyRef"
    ));
    let cross_owner_reference =
        format!("{{\"#\",{value_type_uuid},{{0,{owner_uuid},{cross_owner_value_uuid}}}}}");
    assert!(
        parse_information_register_choice_parameter_value(
            &cross_owner_reference,
            &type_index,
            &object_refs,
        )
        .is_none()
    );
    assert!(
        parse_information_register_fill_value(&cross_owner_reference, &type_index, &object_refs,)
            .is_none()
    );
    let root_self_reference =
        format!("{{\"#\",{value_type_uuid},{{0,{owner_uuid},{root_value_uuid}}}}}");
    assert!(
        parse_information_register_choice_parameter_value(
            &root_self_reference,
            &type_index,
            &object_refs,
        )
        .is_none()
    );
    assert!(
        parse_information_register_fill_value(&root_self_reference, &type_index, &object_refs,)
            .is_none()
    );
    let child_empty_reference = format!(
        "{{\"#\",{value_type_uuid},{{0,{child_owner_uuid},00000000-0000-0000-0000-000000000000}}}}"
    );
    assert!(
        parse_information_register_choice_parameter_value(
            &child_empty_reference,
            &type_index,
            &object_refs,
        )
        .is_none()
    );

    let mut xml = String::new();
    push_metadata_child_choice_parameters_xml(&mut xml, "\t", &parameters);
    assert!(xml.contains(r#"<app:value xsi:type="xs:boolean">true</app:value>"#));
    assert!(xml.contains(r#"<app:value xsi:type="xs:string">value</app:value>"#));
    assert!(xml.contains(r#"<app:value xsi:nil="true"/>"#));
    assert!(xml.contains(r#"<app:value xsi:type="v8:FixedArray">"#));
}

#[test]
fn parses_information_register_choice_form_reference_variants_fail_closed() {
    let owner_uuid = "11111111-1111-4111-8111-111111111111";
    let form_uuid = "22222222-2222-4222-8222-222222222222";
    let wrong_kind_uuid = "33333333-3333-4333-8333-333333333333";
    let unknown_uuid = "44444444-4444-4444-8444-444444444444";
    let other_owner_form_uuid = "55555555-5555-4555-8555-555555555555";
    let mut type_index = BTreeMap::new();
    let object_refs = BTreeMap::new();
    let mut form_refs = BTreeMap::new();
    type_index.insert(
        owner_uuid.to_string(),
        "cfg:CatalogRef.Products".to_string(),
    );
    form_refs.insert(
        form_uuid.to_string(),
        FormSourceReference {
            relative_path: PathBuf::from("Catalogs/Products/Forms/Choice.xml"),
            kind: "Form",
        },
    );
    form_refs.insert(
        wrong_kind_uuid.to_string(),
        FormSourceReference {
            relative_path: PathBuf::from("Catalogs/Products/Templates/Choice.xml"),
            kind: "Template",
        },
    );
    form_refs.insert(
        other_owner_form_uuid.to_string(),
        FormSourceReference {
            relative_path: PathBuf::from("Catalogs/OtherProducts/Forms/Choice.xml"),
            kind: "Form",
        },
    );

    assert!(matches!(
        parse_information_register_choice_form(
            form_uuid,
            &type_index,
            &object_refs,
            &form_refs,
        ),
        Some(MetadataChoiceForm::Reference(ref value))
            if value == "Catalog.Products.Form.Choice"
    ));
    let typed = format!("{{\"#\",{DESIGN_TIME_REF_TYPE_UUID},{{0,{owner_uuid},{form_uuid}}}}}");
    assert!(matches!(
        parse_information_register_choice_form(&typed, &type_index, &object_refs, &form_refs),
        Some(MetadataChoiceForm::Reference(ref value))
            if value == "Catalog.Products.Form.Choice"
    ));
    assert!(parse_information_register_choice_form(
        unknown_uuid,
        &type_index,
        &object_refs,
        &form_refs,
    )
    .is_none());
    assert!(
        parse_information_register_choice_form(
            wrong_kind_uuid,
            &type_index,
            &object_refs,
            &form_refs,
        )
        .is_none()
    );
    let other_owner =
        format!("{{\"#\",{DESIGN_TIME_REF_TYPE_UUID},{{0,{owner_uuid},{other_owner_form_uuid}}}}}");
    assert!(parse_information_register_choice_form(
        &other_owner,
        &type_index,
        &object_refs,
        &form_refs,
    )
    .is_none());
    assert!(
        parse_information_register_choice_form(
            &typed.replace(DESIGN_TIME_REF_TYPE_UUID, FIXED_ARRAY_TYPE_UUID),
            &type_index,
            &object_refs,
            &form_refs,
        )
        .is_none()
    );
}

#[test]
fn information_register_typed_envelopes_require_exact_platform_type_ids() {
    let owner_uuid = "11111111-1111-4111-8111-111111111111";
    let value_uuid = "22222222-2222-4222-8222-222222222222";
    let foreign_type_uuid = "33333333-3333-4333-8333-333333333333";
    let mut type_index = BTreeMap::new();
    let mut object_refs = BTreeMap::new();
    type_index.insert(owner_uuid.to_string(), "cfg:EnumRef.Status".to_string());
    object_refs.insert(
        value_uuid.to_string(),
        "Enum.Status.EnumValue.Active".to_string(),
    );
    let payload = format!("{{0,{owner_uuid},{value_uuid}}}");
    let design_time_ref = format!("{{\"#\",{DESIGN_TIME_REF_TYPE_UUID},{payload}}}");

    assert!(matches!(
        parse_information_register_choice_parameter_value(
            &design_time_ref,
            &type_index,
            &object_refs,
        ),
        Some(MetadataChoiceParameterValue::DesignTimeRef(ref value))
            if value == "Enum.Status.EnumValue.Active"
    ));
    assert!(
        parse_information_register_choice_parameter_value(
            &format!("{{\"#\",{foreign_type_uuid},{payload}}}"),
            &type_index,
            &object_refs,
        )
        .is_none()
    );
    assert!(
        parse_information_register_choice_parameter_value(
            &format!("{{\"#\",{DESIGN_TIME_REF_TYPE_UUID},{{1,{design_time_ref}}}}}"),
            &type_index,
            &object_refs,
        )
        .is_none()
    );
    assert!(
        parse_information_register_choice_parameter_value(
            &format!("{{\"#\",{FIXED_ARRAY_TYPE_UUID},{payload}}}"),
            &type_index,
            &object_refs,
        )
        .is_none()
    );
    let wrong_inner = format!("{{\"#\",{foreign_type_uuid},{payload}}}");
    assert!(
        parse_information_register_choice_parameter_value(
            &format!("{{\"#\",{FIXED_ARRAY_TYPE_UUID},{{1,{wrong_inner}}}}}"),
            &type_index,
            &object_refs,
        )
        .is_none()
    );
    assert!(
        parse_information_register_fill_value(
            &format!("{{\"#\",{foreign_type_uuid},{payload}}}"),
            &type_index,
            &object_refs,
        )
        .is_none()
    );
}

#[test]
fn information_register_fixed_array_values_are_heterogeneous_and_recursive() {
    let owner_uuid = "11111111-1111-4111-8111-111111111111";
    let value_uuid = "22222222-2222-4222-8222-222222222222";
    let type_index = BTreeMap::from([(owner_uuid.to_string(), "cfg:EnumRef.Status".to_string())]);
    let object_refs = BTreeMap::from([(
        value_uuid.to_string(),
        "Enum.Status.EnumValue.Active".to_string(),
    )]);
    let reference =
        format!("{{\"#\",{DESIGN_TIME_REF_TYPE_UUID},{{0,{owner_uuid},{value_uuid}}}}}");
    let nested = format!("{{\"#\",{FIXED_ARRAY_TYPE_UUID},{{2,{{\"B\",1}},{reference}}}}}");
    let value = parse_information_register_choice_parameter_value(
        &format!(
            "{{\"#\",{FIXED_ARRAY_TYPE_UUID},{{6,{{\"U\"}},{{\"S\",\"text\"}},{{\"N\",-2.50}},{{\"D\",20240203040506}},{reference},{nested}}}}}"
        ),
        &type_index,
        &object_refs,
    )
    .unwrap();

    assert!(matches!(
        &value,
        MetadataChoiceParameterValue::FixedArray(values)
            if matches!(values.as_slice(), [
                MetadataChoiceParameterValue::Nil,
                MetadataChoiceParameterValue::String(text),
                MetadataChoiceParameterValue::Decimal(decimal),
                MetadataChoiceParameterValue::DateTime(date_time),
                MetadataChoiceParameterValue::DesignTimeRef(reference),
                MetadataChoiceParameterValue::FixedArray(nested),
            ] if text == "text"
                && decimal == "-2.50"
                && date_time == "2024-02-03T04:05:06"
                && reference == "Enum.Status.EnumValue.Active"
                && matches!(nested.as_slice(), [
                    MetadataChoiceParameterValue::Boolean(true),
                    MetadataChoiceParameterValue::DesignTimeRef(reference),
                ] if reference == "Enum.Status.EnumValue.Active"))
    ));

    let parameters = vec![MetadataChoiceParameter {
        name: "Mixed".to_string(),
        value,
    }];
    let mut xml = String::new();
    push_metadata_child_choice_parameters_xml(&mut xml, "\t", &parameters);
    assert_eq!(
        xml,
        concat!(
            "\t<ChoiceParameters>\r\n",
            "\t\t<app:item name=\"Mixed\">\r\n",
            "\t\t\t<app:value xsi:type=\"v8:FixedArray\">\r\n",
            "\t\t\t\t<v8:Value xsi:nil=\"true\"/>\r\n",
            "\t\t\t\t<v8:Value xsi:type=\"xs:string\">text</v8:Value>\r\n",
            "\t\t\t\t<v8:Value xsi:type=\"xs:decimal\">-2.50</v8:Value>\r\n",
            "\t\t\t\t<v8:Value xsi:type=\"xs:dateTime\">2024-02-03T04:05:06</v8:Value>\r\n",
            "\t\t\t\t<v8:Value xsi:type=\"xr:DesignTimeRef\">Enum.Status.EnumValue.Active</v8:Value>\r\n",
            "\t\t\t\t<v8:Value xsi:type=\"v8:FixedArray\">\r\n",
            "\t\t\t\t\t<v8:Value xsi:type=\"xs:boolean\">true</v8:Value>\r\n",
            "\t\t\t\t\t<v8:Value xsi:type=\"xr:DesignTimeRef\">Enum.Status.EnumValue.Active</v8:Value>\r\n",
            "\t\t\t\t</v8:Value>\r\n",
            "\t\t\t</app:value>\r\n",
            "\t\t</app:item>\r\n",
            "\t</ChoiceParameters>\r\n",
        )
    );

    for malformed in [
        format!("{{\"#\",{FIXED_ARRAY_TYPE_UUID},{{2,{{\"B\",1}}}}}}"),
        format!("{{\"#\",{FIXED_ARRAY_TYPE_UUID},{{1,{{\"B\",1}},{{\"S\",\"extra\"}}}}}}"),
    ] {
        assert!(
            parse_information_register_choice_parameter_value(
                &malformed,
                &type_index,
                &object_refs,
            )
            .is_none()
        );
    }
    let mut too_deep = r#"{"B",1}"#.to_string();
    for _ in 0..=MAX_METADATA_CHOICE_PARAMETER_VALUE_DEPTH {
        too_deep = format!("{{\"#\",{FIXED_ARRAY_TYPE_UUID},{{1,{too_deep}}}}}");
    }
    assert!(
        parse_information_register_choice_parameter_value(&too_deep, &type_index, &object_refs,)
            .is_none()
    );
}

#[test]
