#[test]
fn classifies_information_register_type_sets_and_preserves_partition_order() {
    let specific_type_id = "11111111-1111-4111-8111-111111111111";
    let defined_type_id = "22222222-2222-4222-8222-222222222222";
    let characteristic_type_id = "33333333-3333-4333-8333-333333333333";
    let mut type_index = BTreeMap::new();
    type_index.insert(
        specific_type_id.to_string(),
        "cfg:CatalogRef.Items".to_string(),
    );
    type_index.insert(
        defined_type_id.to_string(),
        "cfg:DefinedType.Custom".to_string(),
    );
    type_index.insert(
        characteristic_type_id.to_string(),
        "cfg:Characteristic.Custom".to_string(),
    );
    let value_types = stable_partition_metadata_types(
        parse_information_register_type_pattern(
            &format!(
                "{{\"Pattern\",{{\"#\",{defined_type_id}}},{{\"S\"}},{{\"#\",{specific_type_id}}},{{\"#\",e61ef7b8-f3e1-4f4b-8ac7-676e90524997}},{{\"#\",474c3bf6-08b5-4ddc-a2ad-989cedf11583}},{{\"B\"}},{{\"#\",{characteristic_type_id}}},{{\"#\",280f5f0e-9c8a-49cc-bf6d-4d296cc17a63}}}}"
            ),
            &type_index,
        )
        .unwrap(),
    );

    assert!(matches!(value_types[0], ConstantValueType::String { .. }));
    assert!(matches!(
        value_types[1],
        ConstantValueType::Reference { ref reference }
            if reference == "cfg:CatalogRef.Items"
    ));
    assert!(matches!(value_types[2], ConstantValueType::Boolean));
    let type_set_names = value_types[3..]
        .iter()
        .map(metadata_type_xml_name)
        .collect::<Vec<_>>();
    assert_eq!(
        type_set_names,
        [
            "cfg:DefinedType.Custom",
            "cfg:CatalogRef",
            "cfg:EnumRef",
            "cfg:Characteristic.Custom",
            "cfg:AnyIBRef",
        ]
    );
    assert!(
        value_types[3..]
            .iter()
            .all(|value| matches!(value, ConstantValueType::ReferenceTypeSet { .. }))
    );

    let xml = format_metadata_types_xml_with_indent(&value_types, "\t");
    assert!(xml.contains("<v8:Type>cfg:CatalogRef.Items</v8:Type>"));
    assert!(xml.contains("<v8:TypeSet>cfg:CatalogRef</v8:TypeSet>"));
    assert!(xml.contains("<v8:TypeSet>cfg:EnumRef</v8:TypeSet>"));
    assert!(
        format_constant_type_xml(&value_types[3])
            .contains("<v8:TypeSet>cfg:DefinedType.Custom</v8:TypeSet>")
    );
    assert!(
        xml.find("<v8:Type>xs:string</v8:Type>").unwrap()
            < xml
                .find("<v8:TypeSet>cfg:DefinedType.Custom</v8:TypeSet>")
                .unwrap()
    );

    assert!(
        parse_information_register_type_pattern(
            "{\"Pattern\",{\"#\",99999999-9999-4999-8999-999999999999}}",
            &type_index,
        )
        .is_none()
    );
}

#[test]
fn parses_detailed_information_register_command_picture_and_parameter_types() {
    let command_uuid = "11111111-1111-4111-8111-111111111111";
    let specific_type_id = "22222222-2222-4222-8222-222222222222";
    let defined_type_id = "33333333-3333-4333-8333-333333333333";
    let characteristic_type_id = "44444444-4444-4444-8444-444444444444";
    let picture_uuid = "55555555-5555-4555-8555-555555555555";
    let unknown_picture_uuid = "66666666-6666-4666-8666-666666666666";
    let empty_descriptor = r#"{4,0,{0},"",-1,-1,1,0,""}"#;
    let type_pattern = format!(
        "{{\"Pattern\",{{\"#\",{defined_type_id}}},{{\"#\",474c3bf6-08b5-4ddc-a2ad-989cedf11583}},{{\"#\",{specific_type_id}}},{{\"#\",e61ef7b8-f3e1-4f4b-8ac7-676e90524997}},{{\"#\",{characteristic_type_id}}},{{\"#\",280f5f0e-9c8a-49cc-bf6d-4d296cc17a63}},{{\"B\"}}}}"
    );
    let command = |descriptor: &str| {
        format!(
            "{{9,{descriptor},2,{{1,\"en\",\"Run command\"}},1,{{0,0,0}},0,{{1,aabb34e1-98c1-4bd0-bf7f-243f95437b44}},{type_pattern},{{3,{{1,0,{command_uuid}}},\"Run\",{{1,\"en\",\"Run\"}},\"comment\",0,0,00000000-0000-0000-0000-000000000000,0}},1,1,0}}"
        )
    };
    let header = MetadataHeader {
        uuid: command_uuid.to_string(),
        name: "Run".to_string(),
        synonyms: vec![("en".to_string(), "Run".to_string())],
        comment: "comment".to_string(),
        template_type_code: None,
    };
    let mut type_index = BTreeMap::new();
    type_index.insert(
        specific_type_id.to_string(),
        "cfg:CatalogRef.Items".to_string(),
    );
    type_index.insert(
        defined_type_id.to_string(),
        "cfg:DefinedType.Custom".to_string(),
    );
    type_index.insert(
        characteristic_type_id.to_string(),
        "cfg:Characteristic.Custom".to_string(),
    );
    let parse_command = |descriptor: &str, object_refs: &BTreeMap<String, String>| {
        let value = command(descriptor);
        let fields = split_1c_braced_fields(&value, 0).unwrap();
        parse_information_register_child_command_properties_from_fields(
            &fields,
            &header,
            &type_index,
            object_refs,
        )
    };
    let properties = parse_command(empty_descriptor, &BTreeMap::new()).unwrap();

    assert_eq!(properties.group.as_deref(), Some("ActionsPanelTools"));
    assert_eq!(properties.representation, "PictureAndText");
    assert_eq!(properties.parameter_use_mode, "Multiple");
    assert!(properties.modifies_data);
    let parameter_type_names = properties
        .command_parameter_types
        .iter()
        .map(metadata_type_xml_name)
        .collect::<Vec<_>>();
    assert_eq!(
        parameter_type_names,
        [
            "cfg:CatalogRef.Items",
            "xs:boolean",
            "cfg:DefinedType.Custom",
            "cfg:EnumRef",
            "cfg:CatalogRef",
            "cfg:Characteristic.Custom",
            "cfg:AnyIBRef",
        ]
    );
    assert!(matches!(
        properties.command_parameter_types[0],
        ConstantValueType::Reference { .. }
    ));
    assert!(matches!(
        properties.command_parameter_types[1],
        ConstantValueType::Boolean
    ));
    assert!(
        properties.command_parameter_types[2..]
            .iter()
            .all(|value| matches!(value, ConstantValueType::ReferenceTypeSet { .. }))
    );
    assert_eq!(properties.picture_ref, None);
    assert!(properties.picture_load_transparent);

    let metadata_command = MetadataChildCommand {
        header: header.clone(),
        properties: Some(properties),
    };
    let mut xml = String::new();
    push_metadata_child_command_xml(&mut xml, &metadata_command);
    assert!(xml.contains("<Group>ActionsPanelTools</Group>"));
    assert!(xml.contains("<v8:Type>cfg:CatalogRef.Items</v8:Type>"));
    assert!(xml.contains("<v8:Type>xs:boolean</v8:Type>"));
    assert!(xml.contains("<v8:TypeSet>cfg:DefinedType.Custom</v8:TypeSet>"));
    assert!(xml.contains("<v8:TypeSet>cfg:EnumRef</v8:TypeSet>"));
    assert!(xml.contains("<v8:TypeSet>cfg:CatalogRef</v8:TypeSet>"));
    assert!(xml.contains("<v8:TypeSet>cfg:Characteristic.Custom</v8:TypeSet>"));
    assert!(xml.contains("<v8:TypeSet>cfg:AnyIBRef</v8:TypeSet>"));
    assert!(
        xml.find("<v8:Type>xs:boolean</v8:Type>").unwrap()
            < xml
                .find("<v8:TypeSet>cfg:DefinedType.Custom</v8:TypeSet>")
                .unwrap()
    );
    assert!(xml.contains("<ParameterUseMode>Multiple</ParameterUseMode>"));
    assert!(xml.contains("<ModifiesData>true</ModifiesData>"));
    assert!(xml.contains("<Representation>PictureAndText</Representation>"));
    assert!(xml.contains("<Picture/>"));
    assert!(xml.contains("<Shortcut/>"));

    let mut owner_xml = "\t<InformationRegister>\r\n\t\t<ChildObjects>\r\n\t\t\t<Resource/>\r\n\t\t</ChildObjects>\r\n\t</InformationRegister>".to_string();
    insert_metadata_child_objects_xml(
        &mut owner_xml,
        "InformationRegister",
        "\t\t\t<Form>Record</Form>\r\n",
    );
    insert_metadata_child_command_objects_xml(
        &mut owner_xml,
        "InformationRegister",
        &[metadata_command],
    );
    assert!(owner_xml.find("<Resource/>").unwrap() < owner_xml.find("<Form>").unwrap());
    assert!(owner_xml.find("<Form>").unwrap() < owner_xml.find("<Command ").unwrap());

    let mut picture_refs = BTreeMap::new();
    picture_refs.insert(picture_uuid.to_string(), "CommonPicture.Run".to_string());
    let picture_descriptor = format!("{{4,1,{{0,{picture_uuid}}},\"\",-1,-1,0,0,\"\"}}");
    let picture_properties = parse_command(&picture_descriptor, &picture_refs).unwrap();
    assert_eq!(
        picture_properties.picture_ref.as_deref(),
        Some("CommonPicture.Run")
    );
    assert!(!picture_properties.picture_load_transparent);
    let picture_command = MetadataChildCommand {
        header: header.clone(),
        properties: Some(picture_properties),
    };
    let mut picture_xml = String::new();
    push_metadata_child_command_xml(&mut picture_xml, &picture_command);
    assert!(picture_xml.contains("<xr:Ref>CommonPicture.Run</xr:Ref>"));
    assert!(picture_xml.contains("<xr:LoadTransparent>false</xr:LoadTransparent>"));

    let print_descriptor =
        format!("{{4,1,{{{STD_PICTURE_PRINT_DESCRIPTOR_CODE}}},\"\",-1,-1,1,0,\"\"}}");
    let print_properties = parse_command(&print_descriptor, &BTreeMap::new()).unwrap();
    assert_eq!(
        print_properties.picture_ref.as_deref(),
        Some("StdPicture.Print")
    );
    assert!(print_properties.picture_load_transparent);
    for (uuid, expected) in [
        (
            "46598f81-5f95-4485-9b33-bfe4fd1276d0",
            "StdPicture.SpreadsheetShowHeaders",
        ),
        ("caf2e58b-ca3d-4b63-82c9-f21f1c9bc9eb", "StdPicture.Setting"),
    ] {
        assert_eq!(common_command_standard_picture_name(uuid), None);
        let descriptor = format!("{{4,1,{{0,{uuid}}},\"\",-1,-1,1,0,\"\"}}");
        let properties = parse_command(&descriptor, &BTreeMap::new()).unwrap();
        assert_eq!(properties.picture_ref.as_deref(), Some(expected));
        assert!(properties.picture_load_transparent);
    }

    let malformed_descriptors = [
        r#"{5,0,{0},"",-1,-1,1,0,""}"#,
        r#"{4,2,{0},"",-1,-1,1,0,""}"#,
        r#"{4,0,{1},"",-1,-1,1,0,""}"#,
        r#"{4,0,{0},"caption",-1,-1,1,0,""}"#,
        r#"{4,0,{0},"",0,-1,1,0,""}"#,
        r#"{4,0,{0},"",-1,0,1,0,""}"#,
        r#"{4,0,{0},"",-1,-1,0,0,""}"#,
        r#"{4,0,{0},"",-1,-1,2,0,""}"#,
        r#"{4,0,{0},"",-1,-1,1,1,""}"#,
        r#"{4,0,{0},"",-1,-1,1,0,"tail"}"#,
        r#"{4,0,{0},"",-1,-1,1,0,"",0}"#,
    ];
    for descriptor in malformed_descriptors {
        assert!(
            parse_information_register_command_picture_descriptor(descriptor, &BTreeMap::new())
                .is_none(),
            "accepted {descriptor}"
        );
    }
    assert!(
        parse_information_register_command_picture_descriptor(
            &format!("{{4,1,{{0,{unknown_picture_uuid}}},\"\",-1,-1,1,0,\"\"}}"),
            &picture_refs,
        )
        .is_none()
    );
    picture_refs.insert(
        unknown_picture_uuid.to_string(),
        "Catalog.Products".to_string(),
    );
    assert!(
        parse_information_register_command_picture_descriptor(
            &format!("{{4,1,{{0,{unknown_picture_uuid}}},\"\",-1,-1,1,0,\"\"}}"),
            &picture_refs,
        )
        .is_none()
    );
}

#[test]
fn appends_register_commands_to_existing_child_objects_block() {
    let register_uuid = "11111111-1111-4111-8111-111111111111";
    let resource_uuid = "22222222-2222-4222-8222-222222222222";
    let command_uuid = "33333333-3333-4333-8333-333333333333";
    let blob = deflate_for_test(
            format!(
                "{{1,\r\n{{33,aaaaaaaa-aaaa-4aaa-8aaa-aaaaaaaaaaaa,aaaaaaaa-aaaa-4aaa-8aaa-aaaaaaaaaaab,aaaaaaaa-aaaa-4aaa-8aaa-aaaaaaaaaaac,aaaaaaaa-aaaa-4aaa-8aaa-aaaaaaaaaaad,aaaaaaaa-aaaa-4aaa-8aaa-aaaaaaaaaaae,aaaaaaaa-aaaa-4aaa-8aaa-aaaaaaaaaaaf,aaaaaaaa-aaaa-4aaa-8aaa-aaaaaaaaaaa1,aaaaaaaa-aaaa-4aaa-8aaa-aaaaaaaaaaa2,aaaaaaaa-aaaa-4aaa-8aaa-aaaaaaaaaaa3,aaaaaaaa-aaaa-4aaa-8aaa-aaaaaaaaaaa4,aaaaaaaa-aaaa-4aaa-8aaa-aaaaaaaaaaa5,aaaaaaaa-aaaa-4aaa-8aaa-aaaaaaaaaaa6,aaaaaaaa-aaaa-4aaa-8aaa-aaaaaaaaaaa7,aaaaaaaa-aaaa-4aaa-8aaa-aaaaaaaaaaa8,\r\n{{0,\r\n{{3,\r\n{{1,0,{register_uuid}}},\"Rates\",{{1,\"en\",\"Rates\"}},\"\"}}\r\n}},\
{{b64d9a41-1642-11d6-a3c7-0050bae0a776,1,\r\n{{5,\r\n{{27,\r\n{{2,\r\n{{3,\r\n{{1,0,{resource_uuid}}},\"Value\",{{1,\"en\",\"Value\"}},\"\"}}\r\n}}\r\n}}\r\n}}\r\n}},\
{{9,\r\n{{3,\r\n{{1,0,{command_uuid}}},\"Import\",{{1,\"en\",\"Import\"}},\"\"}}\r\n}}}}\r\n}}"
            )
            .as_bytes(),
        );

    let extracted = extract_metadata_source_xml_with_refs(
        &blob,
        register_uuid,
        &BTreeMap::new(),
        &BTreeMap::new(),
        &BTreeMap::new(),
        &BTreeMap::new(),
        &BTreeMap::new(),
        &BTreeMap::new(),
        InfobaseConfigSourceVersion::V2_21,
    )
    .unwrap();
    let xml = String::from_utf8(extracted.xml).unwrap();

    assert_eq!(
        extracted.relative_path,
        PathBuf::from("InformationRegisters/Rates.xml")
    );
    assert_eq!(xml.matches("<ChildObjects>").count(), 1);
    assert!(xml.contains(r#"<Resource uuid="22222222-2222-4222-8222-222222222222">"#));
    assert!(xml.contains(r#"<Command uuid="33333333-3333-4333-8333-333333333333">"#));
    assert!(xml.find("<Resource").unwrap() < xml.find("<Command").unwrap());
}

#[test]
fn extracts_enum_xml_with_values_and_native_envelope() {
    let enum_uuid = "11111111-1111-4111-8111-111111111111";
    let ref_type_id = "22222222-2222-4222-8222-222222222221";
    let ref_value_id = "22222222-2222-4222-8222-222222222222";
    let manager_type_id = "33333333-3333-4333-8333-333333333331";
    let manager_value_id = "33333333-3333-4333-8333-333333333332";
    let list_type_id = "44444444-4444-4444-8444-444444444441";
    let list_value_id = "44444444-4444-4444-8444-444444444442";
    let value_open_uuid = "55555555-5555-4555-8555-555555555551";
    let value_closed_uuid = "66666666-6666-4666-8666-666666666661";
    let zero_uuid = "00000000-0000-0000-0000-000000000000";
    let enum_blob = deflate_for_test(
            format!(
                "{{1,\r\n{{20,{ref_type_id},{ref_value_id},{manager_type_id},{manager_value_id},\r\n{{0,\r\n{{3,\r\n{{1,0,{enum_uuid}}},\"Status\",{{1,\"en\",\"Status\"}},\"enum comment\",0,0,{zero_uuid},0}}\r\n}},0,{list_type_id},{list_value_id},{zero_uuid},{zero_uuid},2,1,{zero_uuid},{zero_uuid},{{1,\"en\",\"Statuses\"}},{{0}},{{0}},{{0,{{0}}}},0}},2,\r\n{{aaaaaaaa-aaaa-4aaa-aaaa-aaaaaaaaaaaa,0}},{{bbbbbbbb-bbbb-4bbb-bbbb-bbbbbbbbbbbb,0}},{{cccccccc-cccc-4ccc-cccc-cccccccccccc,0}},\r\n{{dddddddd-dddd-4ddd-dddd-ddddddddddddd,2,\r\n{{{{0,{{3,{{1,0,{value_open_uuid}}},\"Open\",{{1,\"en\",\"Open\"}},\"\"}}}},0}},\r\n{{{{0,{{3,{{1,0,{value_closed_uuid}}},\"Closed\",{{1,\"en\",\"Closed\"}},\"\"}}}},0}}}}\r\n}}"
            )
            .as_bytes(),
        );

    let extracted = extract_metadata_source_xml(
        &enum_blob,
        enum_uuid,
        &BTreeMap::new(),
        &BTreeMap::new(),
        &BTreeMap::new(),
    )
    .unwrap();
    let xml = String::from_utf8(extracted.xml).unwrap();

    assert_eq!(extracted.relative_path, PathBuf::from("Enums/Status.xml"));
    assert!(xml.starts_with("\u{feff}<?xml version=\"1.0\" encoding=\"UTF-8\"?>"));
    assert!(xml.contains(r#"version="2.20""#));
    assert!(!xml.contains("xmlns:pal="));
    assert!(xml.contains(r#"<Enum uuid="11111111-1111-4111-8111-111111111111">"#));
    assert!(xml.contains(r#"<xr:GeneratedType name="EnumRef.Status" category="Ref">"#));
    assert!(xml.contains(&format!("<xr:TypeId>{ref_type_id}</xr:TypeId>")));
    assert!(xml.contains(r#"<xr:GeneratedType name="EnumManager.Status" category="Manager">"#));
    assert!(xml.contains(r#"<xr:GeneratedType name="EnumList.Status" category="List">"#));
    assert!(xml.contains("<Comment>enum comment</Comment>"));
    assert!(xml.contains("<UseStandardCommands>false</UseStandardCommands>"));
    assert!(xml.contains(r#"<xr:StandardAttribute name="Order">"#));
    assert!(xml.contains(r#"<xr:StandardAttribute name="Ref">"#));
    assert!(xml.contains("<Characteristics/>"));
    assert!(xml.contains("<QuickChoice>true</QuickChoice>"));
    assert!(xml.contains("<ChoiceMode>BothWays</ChoiceMode>"));
    assert!(xml.contains("<DefaultListForm/>"));
    assert!(xml.contains("<DefaultChoiceForm/>"));
    assert!(xml.contains("<ListPresentation>"));
    assert!(xml.contains("<v8:content>Statuses</v8:content>"));
    assert!(xml.contains("<ChoiceHistoryOnInput>Auto</ChoiceHistoryOnInput>"));
    assert!(xml.contains(r#"<EnumValue uuid="55555555-5555-4555-8555-555555555551">"#));
    assert!(xml.contains("<Name>Open</Name>"));
    assert!(!xml.contains("<Color>auto</Color>"));
    assert!(xml.contains(r#"<EnumValue uuid="66666666-6666-4666-8666-666666666661">"#));
    assert!(xml.contains("<Name>Closed</Name>"));
    assert!(xml.contains("<Comment/>"));
    assert!(!xml.ends_with("\r\n"));

    let v21 = extract_metadata_source_xml_with_refs(
        &enum_blob,
        enum_uuid,
        &BTreeMap::new(),
        &BTreeMap::new(),
        &BTreeMap::new(),
        &BTreeMap::new(),
        &BTreeMap::new(),
        &BTreeMap::new(),
        InfobaseConfigSourceVersion::V2_21,
    )
    .unwrap();
    let v21_xml = String::from_utf8(v21.xml).unwrap();
    assert!(v21_xml.contains(r#"version="2.21""#));
    assert!(v21_xml.contains(r#"xmlns:pal="http://v8.1c.ru/8.1/data/ui/colors/palette""#));
    assert!(v21_xml.contains("<Color>auto</Color>"));
}

