#[test]
fn selected_metadata_predefined_owner_resolves_generated_type_to_metadata_owner() {
    let register_uuid = "11111111-1111-4111-8111-111111111111";
    let generated_ref_type_uuid = "22222222-2222-4222-8222-222222222222";
    let metadata_owner_uuid = "33333333-3333-4333-8333-333333333333";
    let value_uuid = "44444444-4444-4444-8444-444444444444";
    let row_for_kind = |kind: &str| MetadataTextRow {
        file_name: register_uuid.to_string(),
        text: format!(
            "{{\"#\",{DESIGN_TIME_REF_TYPE_UUID},{{0,{generated_ref_type_uuid},{value_uuid}}}}}"
        ),
        object_code: Some(33),
        header: None,
        kind: Some(kind.to_string()),
        folder: Some("InformationRegisters"),
    };
    let selected = BTreeSet::from([register_uuid.to_string()]);
    let type_index = BTreeMap::from([(
        generated_ref_type_uuid.to_string(),
        "cfg:CatalogRef.Types".to_string(),
    )]);
    let object_refs =
        BTreeMap::from([(metadata_owner_uuid.to_string(), "Catalog.Types".to_string())]);
    let body_owners = BTreeMap::from([(
        metadata_owner_uuid.to_string(),
        BodyOwnerSourceReference {
            kind: "Catalog".to_string(),
            object_path: PathBuf::from("Catalogs/Types"),
        },
    )]);

    for kind in ["InformationRegister", "Catalog", "Document"] {
        let row = row_for_kind(kind);
        assert_eq!(
            selected_metadata_predefined_owner_ids(
                std::slice::from_ref(&row),
                &selected,
                &type_index,
                &object_refs,
                &body_owners,
            ),
            BTreeSet::from([metadata_owner_uuid.to_string()])
        );
    }
    let document = row_for_kind("Document");
    let mut foreign_value_refs = object_refs.clone();
    foreign_value_refs.insert(
        value_uuid.to_string(),
        "Catalog.OtherTypes.Foreign".to_string(),
    );
    assert_eq!(
        selected_metadata_predefined_owner_ids(
            std::slice::from_ref(&document),
            &selected,
            &type_index,
            &foreign_value_refs,
            &body_owners,
        ),
        BTreeSet::from([metadata_owner_uuid.to_string()])
    );
    let mut same_owner_child_refs = object_refs.clone();
    same_owner_child_refs.insert(
        value_uuid.to_string(),
        "Catalog.Types.Attribute.Existing".to_string(),
    );
    assert_eq!(
        selected_metadata_predefined_owner_ids(
            std::slice::from_ref(&document),
            &selected,
            &type_index,
            &same_owner_child_refs,
            &body_owners,
        ),
        BTreeSet::from([metadata_owner_uuid.to_string()])
    );
    assert!(
        parse_information_register_choice_parameter_value(
            &format!(
                "{{\"#\",{DESIGN_TIME_REF_TYPE_UUID},{{0,{generated_ref_type_uuid},{value_uuid}}}}}"
            ),
            &type_index,
            &same_owner_child_refs,
        )
        .is_none()
    );
    let mut same_owner_value_refs = object_refs.clone();
    same_owner_value_refs.insert(value_uuid.to_string(), "Catalog.Types.Existing".to_string());
    assert!(
        selected_metadata_predefined_owner_ids(
            &[document],
            &selected,
            &type_index,
            &same_owner_value_refs,
            &body_owners,
        )
        .is_empty()
    );
    let unsupported = row_for_kind("Report");
    assert!(
        selected_metadata_predefined_owner_ids(
            &[unsupported],
            &selected,
            &type_index,
            &object_refs,
            &body_owners,
        )
        .is_empty()
    );
    let duplicate_owner_uuid = "55555555-5555-4555-8555-555555555555";
    let mut ambiguous_object_refs = object_refs.clone();
    ambiguous_object_refs.insert(
        duplicate_owner_uuid.to_string(),
        "Catalog.Types".to_string(),
    );
    let mut ambiguous_body_owners = body_owners;
    ambiguous_body_owners.insert(
        duplicate_owner_uuid.to_string(),
        BodyOwnerSourceReference {
            kind: "Catalog".to_string(),
            object_path: PathBuf::from("Catalogs/OtherTypes"),
        },
    );
    let row = row_for_kind("Catalog");
    assert!(
        selected_metadata_predefined_owner_ids(
            &[row],
            &selected,
            &type_index,
            &ambiguous_object_refs,
            &ambiguous_body_owners,
        )
        .is_empty()
    );
}

#[test]
fn owner_qualified_predefined_values_resolve_generated_dtr_owners_without_bare_collisions() {
    let first_owner_type_uuid = "11111111-1111-4111-8111-111111111111";
    let second_owner_type_uuid = "22222222-2222-4222-8222-222222222222";
    let third_owner_type_uuid = "33333333-3333-4333-8333-333333333333";
    let shared_value_uuid = "44444444-4444-4444-8444-444444444444";
    let unique_value_uuid = "55555555-5555-4555-8555-555555555555";
    let first_owner = "ChartOfCharacteristicTypes.Domestic";
    let second_owner = "ChartOfCharacteristicTypes.International";
    let first_item = PredefinedItem {
        id: shared_value_uuid.to_string(),
        name: "BankAccounts".to_string(),
        code: String::new(),
        description: String::new(),
        data: PredefinedItemData::Generic {
            value_types: Vec::new(),
            is_folder: false,
        },
        children: vec![PredefinedItem {
            id: unique_value_uuid.to_string(),
            name: "Unique".to_string(),
            code: String::new(),
            description: String::new(),
            data: PredefinedItemData::Generic {
                value_types: Vec::new(),
                is_folder: false,
            },
            children: Vec::new(),
        }],
    };
    let second_item = PredefinedItem {
        id: shared_value_uuid.to_string(),
        name: "BankAccounts".to_string(),
        code: String::new(),
        description: String::new(),
        data: PredefinedItemData::Generic {
            value_types: Vec::new(),
            is_folder: false,
        },
        children: Vec::new(),
    };
    let mut index = BTreeMap::new();
    let mut ambiguous = BTreeSet::new();
    insert_predefined_item_references(
        &mut index,
        &mut ambiguous,
        first_owner,
        &[first_item.clone()],
    )
    .unwrap();
    assert_eq!(
        index.get(shared_value_uuid).map(String::as_str),
        Some("ChartOfCharacteristicTypes.Domestic.BankAccounts")
    );
    insert_predefined_item_references(&mut index, &mut ambiguous, second_owner, &[second_item])
        .unwrap();
    assert!(!index.contains_key(shared_value_uuid));
    assert!(ambiguous.contains(shared_value_uuid));
    assert_eq!(
        index
            .get(&metadata_owner_value_reference_key(
                first_owner,
                shared_value_uuid,
            ))
            .map(String::as_str),
        Some("ChartOfCharacteristicTypes.Domestic.BankAccounts")
    );
    assert_eq!(
        index
            .get(&metadata_owner_value_reference_key(
                second_owner,
                shared_value_uuid,
            ))
            .map(String::as_str),
        Some("ChartOfCharacteristicTypes.International.BankAccounts")
    );
    assert_eq!(
        index.get(unique_value_uuid).map(String::as_str),
        Some("ChartOfCharacteristicTypes.Domestic.Unique")
    );

    let type_index = BTreeMap::from([
        (
            first_owner_type_uuid.to_string(),
            "cfg:ChartOfCharacteristicTypesRef.Domestic".to_string(),
        ),
        (
            second_owner_type_uuid.to_string(),
            "cfg:ChartOfCharacteristicTypesRef.International".to_string(),
        ),
        (
            third_owner_type_uuid.to_string(),
            "cfg:ChartOfCharacteristicTypesRef.Other".to_string(),
        ),
    ]);
    let dtr = |owner_uuid: &str, value_uuid: &str| {
        format!("{{\"#\",{DESIGN_TIME_REF_TYPE_UUID},{{0,{owner_uuid},{value_uuid}}}}}")
    };
    let first_metadata_owner_uuid = "aaaaaaaa-aaaa-4aaa-aaaa-aaaaaaaaaaaa";
    let second_metadata_owner_uuid = "bbbbbbbb-bbbb-4bbb-8bbb-bbbbbbbbbbbb";
    let document_uuid = "cccccccc-cccc-4ccc-8ccc-cccccccccccc";
    let selected_row = MetadataTextRow {
        file_name: document_uuid.to_string(),
        text: format!(
            "{{{}, {}}}",
            dtr(first_owner_type_uuid, shared_value_uuid),
            dtr(second_owner_type_uuid, shared_value_uuid),
        ),
        object_code: Some(40),
        header: None,
        kind: Some("Document".to_string()),
        folder: Some("Documents"),
    };
    let owner_object_refs = BTreeMap::from([
        (
            first_metadata_owner_uuid.to_string(),
            first_owner.to_string(),
        ),
        (
            second_metadata_owner_uuid.to_string(),
            second_owner.to_string(),
        ),
    ]);
    let body_owners = BTreeMap::from([
        (
            first_metadata_owner_uuid.to_string(),
            BodyOwnerSourceReference {
                kind: "ChartOfCharacteristicTypes".to_string(),
                object_path: PathBuf::from("ChartsOfCharacteristicTypes/Domestic"),
            },
        ),
        (
            second_metadata_owner_uuid.to_string(),
            BodyOwnerSourceReference {
                kind: "ChartOfCharacteristicTypes".to_string(),
                object_path: PathBuf::from("ChartsOfCharacteristicTypes/International"),
            },
        ),
    ]);
    assert_eq!(
        selected_metadata_predefined_owner_ids(
            &[selected_row],
            &BTreeSet::from([document_uuid.to_string()]),
            &type_index,
            &owner_object_refs,
            &body_owners,
        ),
        BTreeSet::from([
            first_metadata_owner_uuid.to_string(),
            second_metadata_owner_uuid.to_string(),
        ])
    );
    assert!(matches!(
        parse_information_register_choice_parameter_value(
            &dtr(first_owner_type_uuid, shared_value_uuid),
            &type_index,
            &index,
        ),
        Some(MetadataChoiceParameterValue::DesignTimeRef(ref value))
            if value == "ChartOfCharacteristicTypes.Domestic.BankAccounts"
    ));
    assert!(matches!(
        parse_information_register_choice_parameter_value(
            &dtr(second_owner_type_uuid, shared_value_uuid),
            &type_index,
            &index,
        ),
        Some(MetadataChoiceParameterValue::DesignTimeRef(ref value))
            if value == "ChartOfCharacteristicTypes.International.BankAccounts"
    ));
    assert!(
        parse_information_register_choice_parameter_value(
            &dtr(third_owner_type_uuid, shared_value_uuid),
            &type_index,
            &index,
        )
        .is_none()
    );
    for same_owner_child in [
        "ChartOfCharacteristicTypes.Domestic.Attribute.BankAccounts",
        "ChartOfCharacteristicTypes.Domestic.Form.BankAccounts",
    ] {
        assert!(
            parse_information_register_choice_parameter_value(
                &dtr(first_owner_type_uuid, shared_value_uuid),
                &type_index,
                &BTreeMap::from([(shared_value_uuid.to_string(), same_owner_child.to_string(),)]),
            )
            .is_none()
        );
    }
    assert!(matches!(
        parse_information_register_choice_parameter_value(
            &dtr(first_owner_type_uuid, unique_value_uuid),
            &type_index,
            &BTreeMap::from([(
                unique_value_uuid.to_string(),
                "ChartOfCharacteristicTypes.Domestic.Unique".to_string(),
            )]),
        ),
        Some(MetadataChoiceParameterValue::DesignTimeRef(ref value))
            if value == "ChartOfCharacteristicTypes.Domestic.Unique"
    ));

    let mut metadata_refs = BTreeMap::from([(
        shared_value_uuid.to_string(),
        "Catalog.Foreign.Existing".to_string(),
    )]);
    extend_metadata_owner_value_references(&mut metadata_refs, &index).unwrap();
    assert_eq!(
        metadata_refs.get(shared_value_uuid).map(String::as_str),
        Some("Catalog.Foreign.Existing")
    );
    assert!(!metadata_refs.contains_key(unique_value_uuid));
    assert!(
        metadata_refs.contains_key(&metadata_owner_value_reference_key(
            first_owner,
            unique_value_uuid,
        ))
    );

    let conflict_key = metadata_owner_value_reference_key(first_owner, shared_value_uuid);
    let conflict = BTreeMap::from([(
        conflict_key,
        "ChartOfCharacteristicTypes.Domestic.OtherItem".to_string(),
    )]);
    assert!(extend_metadata_owner_value_references(&mut metadata_refs, &conflict).is_err());

    let mut same_owner_index = BTreeMap::new();
    let mut same_owner_ambiguous = BTreeSet::new();
    insert_predefined_item_references(
        &mut same_owner_index,
        &mut same_owner_ambiguous,
        first_owner,
        &[first_item],
    )
    .unwrap();
    let divergent = PredefinedItem {
        id: shared_value_uuid.to_string(),
        name: "OtherItem".to_string(),
        code: String::new(),
        description: String::new(),
        data: PredefinedItemData::Generic {
            value_types: Vec::new(),
            is_folder: false,
        },
        children: Vec::new(),
    };
    assert!(
        insert_predefined_item_references(
            &mut same_owner_index,
            &mut same_owner_ambiguous,
            first_owner,
            &[divergent],
        )
        .is_err()
    );
}

#[test]
fn extracts_exchange_plan_child_form_and_template_refs_from_current_indexes() {
    let exchange_plan_uuid = "11111111-1111-4111-8111-111111111111";
    let form_uuid = "22222222-2222-4222-8222-222222222222";
    let template_uuid = "33333333-3333-4333-8333-333333333333";
    let tail = exchange_plan_default_owner_tail_for_test();
    let template_collection = format!("{{3daea016-69b7-4ed4-9453-127911372fe6,1,{template_uuid}}}");
    let form_collection = format!("{{87c509ab-3d38-4d67-b379-aca796298578,1,{form_uuid}}}");
    let exchange_plan_raw = exact_exchange_plan_root_with_collections_for_test(
        exchange_plan_uuid,
        "36",
        &tail,
        None,
        [
            "{1a1b4fea-e093-470d-94ff-1d2f16cda2ab,0}",
            &template_collection,
            "{52293f4b-f98c-43ea-a80f-41047ae7ab58,0}",
            &form_collection,
            "{d5207c64-11d5-4d46-bba2-55b7b07ff4eb,0}",
        ],
    );
    let exchange_plan_blob = deflate_for_test(exchange_plan_raw.as_bytes());
    let form_blob = deflate_for_test(
            format!(
                "{{1,\r\n{{0,\r\n{{13,\r\n{{3,\r\n{{1,0,{form_uuid}}},\"NodeForm\",{{1,\"en\",\"Node form\"}},\"\"}},0,1,{{0}}\r\n}}\r\n}},0}}"
            )
            .as_bytes(),
        );
    let template_blob = deflate_for_test(
            format!(
                "{{1,\r\n{{2,4,\r\n{{3,\r\n{{1,0,{template_uuid}}},\"Rules\",{{1,\"en\",\"Rules\"}},\"\"}}\r\n,0}}\r\n}}"
            )
            .as_bytes(),
        );
    let row = |file_name: &str, data: &[u8]| ConfigRow {
        file_name: file_name.to_string(),
        part_no: 0,
        data_size: data.len() as i64,
        binary_hex: encode_hex_for_test(data),
    };
    let rows = vec![
        row(exchange_plan_uuid, &exchange_plan_blob),
        row(form_uuid, &form_blob),
        row(template_uuid, &template_blob),
    ];
    let form_refs = build_form_source_reference_index(&rows);
    let template_refs = build_template_source_reference_index(&rows);

    assert_eq!(
        form_refs
            .get(form_uuid)
            .map(|form_ref| form_ref.relative_path.as_path()),
        Some(Path::new("ExchangePlans/Sync/Forms/NodeForm.xml"))
    );
    assert_eq!(
        template_refs
            .get(template_uuid)
            .map(|template_ref| template_ref.relative_path.as_path()),
        Some(Path::new("ExchangePlans/Sync/Templates/Rules.xml"))
    );

    let extracted = extract_metadata_source_xml_with_refs(
        &exchange_plan_blob,
        exchange_plan_uuid,
        &BTreeMap::new(),
        &BTreeMap::new(),
        &BTreeMap::new(),
        &form_refs,
        &template_refs,
        &BTreeMap::new(),
        InfobaseConfigSourceVersion::V2_21,
    )
    .unwrap();
    let xml = String::from_utf8(extracted.xml).unwrap();

    assert_eq!(
        extracted.relative_path,
        PathBuf::from("ExchangePlans").join("Sync.xml")
    );
    assert!(xml.contains("<ChildObjects>"));
    assert!(xml.contains("<Form>NodeForm</Form>"));
    assert!(xml.contains("<Template>Rules</Template>"));
    assert!(xml.find("</Properties>").unwrap() < xml.find("<ChildObjects>").unwrap());
    assert!(
        xml.find("<Form>NodeForm</Form>").unwrap()
            < xml.find("<Template>Rules</Template>").unwrap()
    );
    assert_eq!(xml.matches("<Form>NodeForm</Form>").count(), 1);
    assert_eq!(xml.matches("<Template>Rules</Template>").count(), 1);
}

fn strict_document_journal_text_for_test(
    journal_uuid: &str,
    name: &str,
    generated_type_ids: [&str; 6],
    root_collections: [&str; 4],
) -> String {
    let [
        selection_type_id,
        selection_value_id,
        list_type_id,
        list_value_id,
        manager_type_id,
        manager_value_id,
    ] = generated_type_ids;
    let [forms, templates, commands, other] = root_collections;
    let zero_uuid = "00000000-0000-0000-0000-000000000000";
    format!(
        "{{1,{{26,{list_type_id},{list_value_id},\
{{0,{{3,{{1,0,{journal_uuid}}},\"{name}\",{{1,\"en\",\"{name}\"}},\"\",0,0,{zero_uuid},0}}}},\
aaaaaaaa-aaaa-4aaa-8aaa-aaaaaaaaaaaa,1,{{0}},0,{manager_type_id},{manager_value_id},\
{selection_type_id},{selection_value_id},{{0}},{zero_uuid},{{0}},{{0}},{{0}}}},\
4,{forms},{templates},{commands},{other}}}"
    )
}

#[test]
fn extracts_four_document_journal_generated_type_cohorts_in_native_order() {
    for (journal_uuid, name, ids) in [
        (
            "11000000-0000-4000-8000-000000000001",
            "Interactions",
            [
                "10000000-0000-4000-8000-000000000001",
                "10000000-0000-4000-8000-000000000002",
                "10000000-0000-4000-8000-000000000003",
                "10000000-0000-4000-8000-000000000004",
                "10000000-0000-4000-8000-000000000005",
                "10000000-0000-4000-8000-000000000006",
            ],
        ),
        (
            "22000000-0000-4000-8000-000000000002",
            "MailJournal",
            [
                "20000000-0000-4000-8000-000000000001",
                "20000000-0000-4000-8000-000000000002",
                "20000000-0000-4000-8000-000000000003",
                "20000000-0000-4000-8000-000000000004",
                "20000000-0000-4000-8000-000000000005",
                "20000000-0000-4000-8000-000000000006",
            ],
        ),
        (
            "33000000-0000-4000-8000-000000000003",
            "Calls",
            [
                "30000000-0000-4000-8000-000000000001",
                "30000000-0000-4000-8000-000000000002",
                "30000000-0000-4000-8000-000000000003",
                "30000000-0000-4000-8000-000000000004",
                "30000000-0000-4000-8000-000000000005",
                "30000000-0000-4000-8000-000000000006",
            ],
        ),
        (
            "44000000-0000-4000-8000-000000000004",
            "Archive",
            [
                "40000000-0000-4000-8000-000000000001",
                "40000000-0000-4000-8000-000000000002",
                "40000000-0000-4000-8000-000000000003",
                "40000000-0000-4000-8000-000000000004",
                "40000000-0000-4000-8000-000000000005",
                "40000000-0000-4000-8000-000000000006",
            ],
        ),
    ] {
        let text = strict_document_journal_text_for_test(
            journal_uuid,
            name,
            ids,
            ["{0}", "{0}", "{0}", "{0}"],
        );
        let blob = deflate_for_test(text.as_bytes());
        let extracted = extract_metadata_source_xml(
            &blob,
            journal_uuid,
            &BTreeMap::new(),
            &BTreeMap::new(),
            &BTreeMap::new(),
        )
        .unwrap_or_else(|| panic!("failed positive {name}"));
        let xml = String::from_utf8(extracted.xml).unwrap();

        assert_eq!(
            extracted.relative_path,
            PathBuf::from("DocumentJournals").join(format!("{name}.xml"))
        );
        assert_eq!(
            xml.matches("<xr:GeneratedType ").count(),
            3,
            "{name}: {xml}"
        );
        let selection = xml
            .find(&format!(
                r#"<xr:GeneratedType name="DocumentJournalSelection.{name}" category="Selection">"#
            ))
            .unwrap();
        let list = xml
            .find(&format!(
                r#"<xr:GeneratedType name="DocumentJournalList.{name}" category="List">"#
            ))
            .unwrap();
        let manager = xml
            .find(&format!(
                r#"<xr:GeneratedType name="DocumentJournalManager.{name}" category="Manager">"#
            ))
            .unwrap();
        assert!(selection < list && list < manager, "{name}: {xml}");
        for (prefix, category, type_id, value_id) in [
            ("DocumentJournalSelection", "Selection", ids[0], ids[1]),
            ("DocumentJournalList", "List", ids[2], ids[3]),
            ("DocumentJournalManager", "Manager", ids[4], ids[5]),
        ] {
            let exact_block = format!(
                "\t\t\t<xr:GeneratedType name=\"{prefix}.{name}\" category=\"{category}\">\r\n\
\t\t\t\t<xr:TypeId>{type_id}</xr:TypeId>\r\n\
\t\t\t\t<xr:ValueId>{value_id}</xr:ValueId>\r\n\
\t\t\t</xr:GeneratedType>\r\n"
            );
            assert!(
                xml.contains(&exact_block),
                "wrong {category} pair in {name}: {xml}"
            );
        }
        assert!(xml.find("<InternalInfo>").unwrap() < xml.find("<Properties>").unwrap());
        for unrelated in [
            "<UseStandardCommands>",
            "<DefaultListForm>",
            "<RegisteredDocuments>",
            "<StandardAttributes>",
            "<Column ",
        ] {
            assert!(
                !xml.contains(unrelated),
                "unexpected {unrelated} in {name}: {xml}"
            );
        }
    }
}

